                }
            }
            ;

            // 2차원 배열의 행(Row)과 열(Col)의 길이를 구합니다.
            int rows = IronClad1.GetLength(0);
            int cols = IronClad1.GetLength(1);

            for (int r = 0; r < rows; r++)
            {
                for (int c = 0; c < cols; c++)
                {
                    // 1. 16진수 컬러값을 읽어옴
                    uint hexColor = IronClad1[r, c];

                    // 2. 16진수를 알파벳 키워드로 변환
                    char key = GetKey(hexColor);

                    // 3. 알파벳 키워드에 따라 색상을 입혀서 콘솔에 출력
                    PrintPixel(key);
                }
                // 한 행이 끝나면 줄바꿈
                Console.WriteLine();
            }

            // 출력 완료 후 색상 리셋 및 대기
            Console.ResetColor();
            Console.ReadLine();
        }

        private static readonly Dictionary<uint, char> ColorMap = new Dictionary<uint, char>()
        {
            { 0x00000000, '.' }, // 투명 배경

            // 블루 / 네이비 계열
            { 0xff181e29, 'D' }, // Dark Navy
            { 0xff171e44, 'N' }, // Navy
            { 0xff243c59, 'B' }, // Base Blue
            { 0xff2c3572, 'm' }, // mid navy
            { 0xff335c84, 'M' }, // Mid Navy
            { 0xff335680, 'v' }, // 중간 파랑
            { 0xff4c84bc, 'L' }, // Light Blue
            { 0xff4882bb, 'l' }, // light blue
            { 0xff8bbff4, 'H' }, // Highlight Blue
            { 0xff3b3be8, 'P' }, // Point Blue

            // 그레이 / 화이트 계열
            { 0xff939395, 'g' }, // gray
            { 0xffa3a3a8, 'G' }, // Gray
            { 0xffbababa, 'S' }, // Silver
            { 0xffd7d7db, 'W' }, // White 그레이

            // 카키 / 베이지 / 녹색 계열
            { 0xff2a2922, 'b' }, // brown
            { 0xff292821, 'k' }, // 카키 브라운
            { 0xff3d3b30, 'y' }, // 찰흙 갈색
            { 0xff575444, 'K' }, // Khaki
            { 0xff726e58, 'Y' }, // 밝은 흙색
            { 0xff373f37, 'd' }, // dark green
            { 0xff758575, 'V' }, // 녹색 (Vegetation)
            { 0xffc6c6ae, 'c' }, // cream / skin
            { 0xffa8a894, 'C' }, // Cream

            // 블랙
            { 0xff000000, 'X' }  // Black
        };

        public static char GetKey(uint color)
        {
            // 등록된 색상이면 해당 알파벳을, 등록되지 않은 색상이면 물음표(?)를 반환합니다.
            return ColorMap.TryGetValue(color, out char key) ? key : '?';
        }

        public static void PrintPixel(char key)
        {
            switch (key)
            {
                case '.': // 투명 배경: 색상을 바꾸지 않고 공백 2칸 출력 후 종료
                    Console.Write("  ");
                    return;

                // ==================== 블루 / 네이비 계열 ====================
                case 'D': // Dark Navy (암청색)
                case 'N': // Navy (어두운 청색)
                case 'B': // Base Blue (기본 네이비)
                case 'm': // mid navy (중간 네이비 1)
                    Console.ForegroundColor = ConsoleColor.DarkBlue;
                    break;
                case 'M': // Mid Navy (중간 네이비 2)
                case 'v': // 중간 파랑
                case 'L': // Light Blue (밝은 파랑 1)
                case 'l': // light blue (밝은 파랑 2)
                    Console.ForegroundColor = ConsoleColor.Blue;
                    break;
                case 'H': // Highlight Blue (하늘색)
                    Console.ForegroundColor = ConsoleColor.Cyan;
                    break;
                case 'P': // Point Blue (선명한 파랑)
                    Console.ForegroundColor = ConsoleColor.DarkCyan;
                    break;

                // ==================== 그레이 / 화이트 계열 ====================
                case 'g': // gray (중간 회색)
                case 'G': // Gray (밝은 회색)
                case 'S': // Silver (은회색)
                    Console.ForegroundColor = ConsoleColor.Gray;
                    break;
                case 'W': // White 그레이
                    Console.ForegroundColor = ConsoleColor.White;
                    break;

                // ==================== 카키 / 베이지 / 녹색 계열 ====================
                case 'b': // brown (어두운 가죽 갈색)
                case 'k': // 카키 브라운
                case 'y': // 찰흙 갈색
                    Console.ForegroundColor = ConsoleColor.DarkYellow; // 콘솔의 갈색 표현
                    break;
                case 'K': // Khaki (카키)
                case 'Y': // 밝은 흙색
                case 'c': // cream / skin (살구 크림색)
                case 'C': // Cream (어두운 크림색)
                    Console.ForegroundColor = ConsoleColor.Yellow; // 밝은 가죽/피부 표현
                    break;
                case 'd': // dark green (어두운 카키 그린)
                    Console.ForegroundColor = ConsoleColor.DarkGreen;
                    break;
                case 'V': // 녹색 (Vegetation)
                    Console.ForegroundColor = ConsoleColor.Green;
                    break;

                // ==================== 블랙 ====================
                case 'X': // Black
                    Console.ForegroundColor = ConsoleColor.Black;
                    break;

                default:
                    Console.ResetColor();
                    break;
            }

            // 색상이 지정된 후 네모 박스(픽셀) 출력 (이미지 코드와 동일하게 공백을 포함한 형태로 맞춤)
            Console.Write("■");
        }
    }
